				CreateSprite(BMDStruct, ObjectStruct, effectInfo.BonePlayer, effectInfo.EffectID, effectInfo.Size, effectInfo.R, effectInfo.B, effectInfo.G, effectInfo.PosX, effectInfo.PosY, effectInfo.PosZ)					elseif effectInfo.EffectType == 1 then						CreateParticle(BMDStruct, ObjectStruct, effectInfo.BonePlayer, effectInfo.EffectID, effectInfo.EffectLv, effectInfo.Size, effectInfo.R, effectInfo.B, effectInfo.G, effectInfo.PosX, effectInfo.PosY, effectInfo.PosZ)					elseif effectInfo.EffectType == 2 then						CreateSkill(BMDStruct, ObjectStruct, effectInfo.BonePlayer, effectInfo.EffectID, effectInfo.EffectLv, effectInfo.Size, effectInfo.R, effectInfo.B, effectInfo.G, effectInfo.PosX, effectInfo.PosY, effectInfo.PosZ)					end				end			end		end	endend